mapper.select:
SELECT COALESCE(SUM(total_study_time), 0)
FROM student_course
WHERE student_id = #{studentId}

SELECT COALESCE(SUM(duration), 0)
FROM learning_record
WHERE student_id = #{studentId}
  AND DATE(COALESCE(start_time, created_time)) >= #{startDate}
  AND DATE(COALESCE(start_time, created_time)) <= #{endDate}

SELECT
    DATE(COALESCE(start_time, created_time)) AS date,
    SUM(duration) AS studyTime
FROM learning_record
WHERE student_id = #{studentId}

    AND DATE(COALESCE(start_time, created_time)) >= #{startDate}


    AND DATE(COALESCE(start_time, created_time)) <= #{endDate}

GROUP BY DATE(COALESCE(start_time, created_time))
ORDER BY date ASC
